{% set customer_name = doc.party_name %}
{% set patient = frappe.db.get_value('Patient', {'customer': customer_name}, ['name', 'patient_name', 'address_line1', 'city', 'zip_code'], as_dict=1) if customer_name else None %}

<style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');

    @page { size: A4; margin: 0; }

    .s2w-inv {
        font-family: 'Inter', -apple-system, Arial, sans-serif;
        width: 100%;
        min-height: 1120px;
        padding: 44px 52px 56px 52px;
        color: #1e1e1e;
        position: relative;
        background: #fff;
        box-sizing: border-box;
        overflow: hidden;
    }

    /* ===== WATERMARK: Large circle arc ===== */
    .s2w-inv .wm-circle {
        position: absolute;
        top: -100px;
        left: -100px;
        width: 460px;
        height: 460px;
        border-radius: 50%;
        background: rgba(200, 200, 200, 0.12);
        z-index: 0;
        pointer-events: none;
    }

    /* ===== WATERMARK: S2W text ===== */
    .s2w-inv .wm-text {
        position: absolute;
        top: -25px;
        left: -30px;
        font-size: 290px;
        font-weight: 900;
        color: rgba(0,0,0,0.025);
        letter-spacing: -18px;
        z-index: 0;
        pointer-events: none;
        line-height: 0.85;
    }

    /* ===== DOT PATTERN ===== */
    .s2w-inv .wm-dots {
        position: absolute;
        top: 300px;
        left: 52px;
        right: 52px;
        bottom: 220px;
        background-image: radial-gradient(circle, #c5d86d40 2px, transparent 2px);
        background-size: 34px 34px;
        z-index: 0;
        pointer-events: none;
    }

    /* ===== HEADER ===== */
    .s2w-inv .inv-header {
        display: flex;
        justify-content: space-between;
        align-items: flex-start;
        position: relative;
        z-index: 1;
        margin-bottom: 22px;
    }

    /* CSS Logo matching the reference */
    .s2w-inv .logo-wrap {
        display: flex;
        align-items: center;
        gap: 12px;
    }

    .s2w-inv .logo-icon {
        width: 64px;
        height: 64px;
        border-radius: 50%;
        background: #2d3436;
        display: flex;
        align-items: center;
        justify-content: center;
        box-shadow: 0 0 0 4px rgba(200,200,200,0.3);
    }

    .s2w-inv .logo-icon span {
        font-size: 22px;
        font-weight: 900;
        letter-spacing: -1px;
    }

    .s2w-inv .logo-icon .s-letter { color: #C1E12F; }
    .s2w-inv .logo-icon .two { color: #fff; }
    .s2w-inv .logo-icon .w-letter { color: #fff; }

    .s2w-inv .logo-text-group {
        display: flex;
        flex-direction: column;
    }

    .s2w-inv .logo-main-text {
        font-size: 30px;
        font-weight: 800;
        color: #2d3436;
        letter-spacing: -1px;
        line-height: 1;
    }

    .s2w-inv .logo-main-text .two-green {
        color: #C1E12F;
        font-weight: 900;
    }

    .s2w-inv .logo-subtitle {
        background: #C1E12F;
        color: #fff;
        font-size: 8px;
        font-weight: 800;
        text-transform: uppercase;
        letter-spacing: 3px;
        padding: 3px 6px;
        margin-top: 3px;
        width: fit-content;
    }

    /* Quotation Title */
    .s2w-inv .inv-title-block {
        text-align: right;
        padding-top: 8px;
    }

    .s2w-inv .inv-title {
        font-size: 38px;
        font-weight: 900;
        color: #1e1e1e;
        letter-spacing: -1px;
        margin: 0;
        line-height: 1;
    }

    .s2w-inv .inv-meta {
        font-size: 12.5px;
        color: #666;
        margin-top: 8px;
        line-height: 1.7;
    }

    /* ===== PATIENT INFO ===== */
    .s2w-inv .patient-block {
        position: relative;
        z-index: 1;
        margin-bottom: 18px;
        font-size: 13.5px;
        line-height: 1.7;
    }

    .s2w-inv .patient-block .lbl {
        color: #888;
    }

    /* ===== VALIDITY NOTICE ===== */
    .s2w-inv .validity-notice {
        position: relative;
        z-index: 1;
        background: #fafae8;
        border: 1px solid #e8e8c8;
        border-radius: 4px;
        padding: 8px 14px;
        font-size: 12px;
        color: #666;
        margin-bottom: 18px;
    }

    /* ===== TABLE ===== */
    .s2w-inv .tbl-header {
        display: flex;
        align-items: center;
        border-top: 2.5px solid #2d3436;
        border-bottom: 1px solid #ccc;
        background: linear-gradient(180deg, #fafae8 0%, #f5f5dc 100%);
        padding: 10px 14px;
        font-weight: 700;
        font-size: 13px;
        position: relative;
        z-index: 1;
    }

    .s2w-inv .tbl-header .c1 { flex: 3; }
    .s2w-inv .tbl-header .c2 { flex: 0.8; text-align: center; }
    .s2w-inv .tbl-header .c3 { flex: 1.2; text-align: center; }
    .s2w-inv .tbl-header .c4 { flex: 1; text-align: right; }

    .s2w-inv .tbl-body {
        position: relative;
        z-index: 1;
        min-height: 440px;
    }

    .s2w-inv .tbl-row {
        display: flex;
        align-items: flex-start;
        padding: 11px 14px;
        font-size: 13px;
        border-bottom: 1px solid #eee;
    }

    .s2w-inv .tbl-row .c1 { flex: 3; font-weight: 600; }
    .s2w-inv .tbl-row .c2 { flex: 0.8; text-align: center; }
    .s2w-inv .tbl-row .c3 { flex: 1.2; text-align: center; }
    .s2w-inv .tbl-row .c4 { flex: 1; text-align: right; font-weight: 700; }

    .s2w-inv .item-sub {
        font-size: 10.5px;
        color: #999;
        font-weight: 400;
        margin-top: 2px;
    }

    /* ===== TOTALS ===== */
    .s2w-inv .totals-wrap {
        display: flex;
        justify-content: flex-end;
        position: relative;
        z-index: 1;
        margin-top: 14px;
    }

    .s2w-inv .totals-box { width: 280px; }

    .s2w-inv .tot-row {
        display: flex;
        justify-content: space-between;
        padding: 5px 14px;
        font-size: 13px;
    }

    .s2w-inv .tot-row.grand {
        font-weight: 900;
        font-size: 16px;
        border-top: 2.5px solid #2d3436;
        margin-top: 6px;
        padding-top: 10px;
    }

    /* ===== FOOTER ===== */
    .s2w-inv .inv-footer {
        position: absolute;
        bottom: 44px;
        left: 52px;
        right: 52px;
        z-index: 1;
    }

    .s2w-inv .bank-bar {
        border-top: 2.5px solid #2d3436;
        border-bottom: 1px solid #ccc;
        background: linear-gradient(180deg, #fafae8 0%, #f5f5dc 100%);
        padding: 8px 14px;
        font-weight: 700;
        font-size: 13px;
    }

    .s2w-inv .foot-cols {
        display: flex;
        justify-content: space-between;
        align-items: flex-end;
        padding: 14px 14px 0 14px;
    }

    .s2w-inv .bank-det {
        font-size: 13px;
        line-height: 1.65;
    }

    .s2w-inv .contact-col {
        text-align: right;
        font-size: 13px;
    }

    .s2w-inv .ct-row {
        display: flex;
        align-items: center;
        justify-content: flex-end;
        gap: 8px;
        margin-bottom: 5px;
    }

    .s2w-inv .ct-icon {
        width: 22px;
        height: 22px;
        border-radius: 50%;
        background: #2d3436;
        color: #fff;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        font-size: 12px;
        line-height: 1;
    }

    /* Green accent bar */
    .s2w-inv .accent-bar {
        position: absolute;
        bottom: 14px;
        right: 52px;
        width: 150px;
        height: 10px;
        background: linear-gradient(90deg, #d4e857, #C1E12F);
        border-radius: 5px;
    }
</style>

<div class="s2w-inv">
    <!-- Watermarks -->
    <div class="wm-circle"></div>
    <div class="wm-text">S2W</div>
    <div class="wm-dots"></div>

    <!-- Header -->
    <div class="inv-header">
        <div class="logo-wrap">
            <div class="logo-icon">
                <span><span class="s-letter">s</span><span class="two">2</span><span class="w-letter">w</span></span>
            </div>
            <div class="logo-text-group">
                <div class="logo-main-text">slim<span class="two-green">2</span>well</div>
                <div class="logo-subtitle">wellness simplified</div>
            </div>
        </div>
        <div class="inv-title-block">
            <h1 class="inv-title">QUOTATION</h1>
            <div class="inv-meta">
                Quote No: <strong>{{ doc.name }}</strong><br>
                Date: <strong>{{ frappe.utils.formatdate(doc.transaction_date) }}</strong><br>
                Valid Till: <strong>{{ frappe.utils.formatdate(doc.valid_till) if doc.valid_till else 'N/A' }}</strong>
            </div>
        </div>
    </div>

    <!-- Patient Info -->
    <div class="patient-block">
        <span class="lbl">Patient Name:</span> {{ patient.patient_name if patient else doc.customer_name or doc.party_name or '' }}<br>
        <span class="lbl">Address:</span>
        {% if patient and patient.address_line1 %}
            {{ patient.address_line1 }}{% if patient.city %}, {{ patient.city }}{% endif %}{% if patient.zip_code %}, {{ patient.zip_code }}{% endif %}
        {% elif doc.address_display %}
            {{ doc.address_display | striptags }}
        {% endif %}
    </div>

    <!-- Table Header -->
    <div class="tbl-header">
        <div class="c1">Description</div>
        <div class="c2">Qty</div>
        <div class="c3">Unit Price</div>
        <div class="c4">Amount</div>
    </div>

    <!-- Table Body -->
    <div class="tbl-body">
        {% for item in doc.items %}
        <div class="tbl-row">
            <div class="c1">
                {{ item.item_name or item.item_code }}
                {% if item.description and item.description != item.item_name %}
                    <div class="item-sub">{{ item.description | striptags | truncate(90) }}</div>
                {% endif %}
            </div>
            <div class="c2">{{ item.qty | int if item.qty == item.qty | int else item.qty }}</div>
            <div class="c3">R {{ '{:,.2f}'.format(item.rate) }}</div>
            <div class="c4">R {{ '{:,.2f}'.format(item.amount) }}</div>
        </div>
        {% endfor %}
    </div>

    <!-- Totals -->
    <div class="totals-wrap">
        <div class="totals-box">
            <div class="tot-row">
                <span>Subtotal</span>
                <span>R {{ '{:,.2f}'.format(doc.total) }}</span>
            </div>
            {% if doc.total_taxes_and_charges %}
            <div class="tot-row">
                <span>VAT (15%)</span>
                <span>R {{ '{:,.2f}'.format(doc.total_taxes_and_charges) }}</span>
            </div>
            {% endif %}
            {% if doc.discount_amount %}
            <div class="tot-row">
                <span>Discount</span>
                <span>- R {{ '{:,.2f}'.format(doc.discount_amount) }}</span>
            </div>
            {% endif %}
            <div class="tot-row grand">
                <span>Total</span>
                <span>R {{ '{:,.2f}'.format(doc.grand_total) }}</span>
            </div>
        </div>
    </div>

    <!-- Footer -->
    <div class="inv-footer">
        <div class="bank-bar">Banking Details:</div>
        <div class="foot-cols">
            <div class="bank-det">
                <strong>Slim2Well Pty Ltd</strong><br>
                Standard Bank<br>
                Code 052650<br>
                Account 032988265
            </div>
            <div class="contact-col">
                <div class="ct-row">
                    www.slim2well.com
                    <span class="ct-icon">
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="2" y1="12" x2="22" y2="12"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg>
                    </span>
                </div>
                <div class="ct-row">
                    social@slim2well.com
                    <span class="ct-icon">
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="4" width="20" height="16" rx="2"/><polyline points="22,7 12,13 2,7"/></svg>
                    </span>
                </div>
            </div>
        </div>
    </div>

    <div class="accent-bar"></div>
</div>
